  ('chatgpt', 'ChatGPT', 'The leading AI conversational model.', 'OpenAI''s flagship conversational agent. Excellent for writing essays, brainstorming, editing copy, drafting articles, and translating languages. Supports advanced custom GPTs, image uploads, and advanced data analysis.', 'Writing', ARRAY['Content writing', 'Copy editing', 'Translating', 'Brainstorming'], 'Freemium', 'Free access, Plus at $20/month', ARRAY['Advanced reasoning (GPT-4o)', 'DALL-E 3 image generation', 'Voice conversations', 'Custom GPT marketplace', 'Advanced Data Analysis'], ARRAY['Web', 'iOS', 'Android', 'macOS', 'Windows'], 'https://chatgpt.com', 4.5, 3, 1297, true, NULL, NULL, 75.1),
  ('gemini', 'Gemini', 'Google''s official multimodal AI assistant.', 'Google Gemini is a highly advanced conversational agent developed by Google. Built from the ground up to be multimodal, it seamlessly processes text, code, images, audio, and video context. It integrates directly with your Google Workspace (Docs, Gmail, Sheets) to search, synthesize, and compose documents in real time.', 'Writing', ARRAY['Workspace docs integration', 'Image & audio inputs', 'Ultrafast response speeds', 'Google Search grounding'], 'Freemium', 'Free basic access, Gemini Advanced at $20/month', ARRAY['Workspace docs integration', 'Image & audio inputs', 'Ultrafast response speeds', 'Google Search grounding', 'Complex coding assistance'], ARRAY['Web', 'Android', 'iOS'], 'https://gemini.google.com', 4.7, 3, 1304, true, NULL, NULL, 75.5),
  ('claude', 'Claude', 'Superb writing style and deep reasoning.', 'Developed by Anthropic, Claude is known for its highly nuanced, natural writing style, extensive context windows, and advanced reasoning capabilities. Claude 3.5 Sonnet sets benchmarks for analytical writing and logical coding tasks.', 'Writing', ARRAY['Long-form article writing', 'Document summarization', 'Creative writing', 'Technical documentation'], 'Freemium', 'Free access, Pro at $20/month', ARRAY['Artifacts panel', 'Project workspaces', '200k token context window', 'Nuanced prose generation', 'Exceptional code explanation'], ARRAY['Web', 'iOS', 'macOS', 'Windows'], 'https://claude.ai', 4.5, 3, 1297, true, NULL, NULL, 74.7),
  ('microsoft-copilot', 'Microsoft Copilot', 'Your everyday AI companion for Office and Windows.', 'Microsoft Copilot is an intelligent assistant integrated into Windows, Office 365, Edge, and Bing. It summarizes emails, generates PowerPoint outlines, drafts Word documents, and automates analysis in Excel sheets.', 'Productivity', ARRAY['Corporate document writing', 'Slides preparation helper', 'Excel sheet automation', 'Meeting summaries transcription'], 'Freemium', 'Free on Web & Windows, Pro at $20/month', ARRAY['Office App integrations', 'PowerPoint slides auto-builder', 'Bing Search live sources', 'GPT-4o text replies', 'Windows settings execution'], ARRAY['Windows', 'macOS', 'Web', 'iOS', 'Android'], 'https://copilot.microsoft.com', 4.5, 3, 1292, true, NULL, NULL, 73.6),
  ('perplexity', 'Perplexity AI', 'AI search engine with live sources and citations.', 'Perplexity AI is a conversational search engine that delivers real-time cited responses to complex questions. Combining models like Claude and GPT with a web crawler, it serves as an alternative to standard search engines.', 'Productivity', ARRAY['Academic literature reviews', 'Fact-checking queries', 'Business intelligence search', 'Tech documentation research'], 'Freemium', 'Free searches, Pro with advanced models at $20/mo', ARRAY['Active citations linking', 'Reddit/YouTube focus filters', 'PDF document analysis uploads', 'Model picker (Claude/GPT/Llama)', 'Shared search folders'], ARRAY['Web', 'iOS', 'Android', 'Chrome Extension'], 'https://perplexity.ai', 4.6, 3, 1293, true, NULL, NULL, 73.4),
  ('apple-intelligence', 'Apple Intelligence', 'Personal intelligence system for iPhone, iPad, and Mac.', 'Apple Intelligence is a personal intelligence system integrated deeply into iOS 18, iPadOS 18, and macOS Sequoia. It harnesses the power of Apple silicon to understand and create language and images, take action across apps, and draw from personal context.', 'Productivity', ARRAY['Writing tools proofreading', 'Image Playground generation', 'Siri application control', 'Notification priority summaries'], 'Free', 'Free on supported Apple devices', ARRAY['On-device processing', 'Private Cloud Compute security', 'ChatGPT integration option', 'Genmoji custom emojis', 'Clean Up photo editor'], ARRAY['iOS', 'macOS', 'iPadOS'], 'https://www.apple.com/apple-intelligence', 4.7, 3, 1309, true, NULL, NULL, 76.5),
  ('meta-ai', 'Meta AI', 'AI assistant across Meta social apps and web.', 'Meta AI is a virtual assistant built on open-source Llama models. It integrates directly into WhatsApp, Instagram, Messenger, and Facebook to answer questions, generate images on-the-fly, translate chats, and summarize social threads instantly.', 'Writing', ARRAY['Social media chat help', 'Instant image generation', 'Chatbot conversations', 'General search requests'], 'Free', '100% Free', ARRAY['Meta social integrations', 'Llama 3 speeds', 'Imagine prompt-to-image engine', 'Real-time search citations'], ARRAY['Web', 'WhatsApp', 'Instagram', 'Messenger'], 'https://meta.ai', 4.7, 3, 1294, true, NULL, NULL, 73.4),
  ('grok', 'Grok by xAI', 'Witty AI assistant with real-time news search.', 'Grok is xAI''s conversational search assistant integrated directly into X (Twitter). Grok stands out by having active access to real-time posts, news flashes, and trending topics worldwide, answering queries with wit and humor.', 'Writing', ARRAY['Real-time news search', 'Witty text drafts', 'Trending topic analysis', 'Multimodal uploads'], 'Paid', 'Included with X Premium ($8-$16/month)', ARRAY['Real-time posts lookup', 'Fun & Normal mode toggles', 'Llama/xAI logic models', 'Code drafting'], ARRAY['Web', 'iOS', 'Android'], 'https://x.com/i/grok', 4.3, 3, 1290, true, NULL, NULL, 75.9),
  ('flux-1', 'FLUX.1 by Black Forest Labs', 'State-of-the-art open image generation model.', 'FLUX.1 is a suite of advanced text-to-image models developed by Black Forest Labs. It sets new benchmarks in image quality, prompt adherence, detailed text rendering, and style variety, powering image engines across major platforms.', 'Image Generation', ARRAY['Photorealistic art generation', 'Text rendering in graphics', 'Fine-art styling illustrations', 'Advertising banner design'], 'Freemium', 'Free open model, Pro API pricing', ARRAY['12 billion parameters scale', 'Exceptional prompt compliance', 'Crisp text spelling', 'Open weights download', 'High speed generation'], ARRAY['Web', 'Windows', 'Linux', 'macOS'], 'https://blackforestlabs.ai', 4.5, 3, 1302, true, NULL, 'black-forest-labs/flux', 76.2),
  ('deepseek', 'DeepSeek R1', 'Open-source reasoning model rivaling OpenAI o1.', 'DeepSeek R1 is a highly advanced, open-source reasoning model developed by DeepSeek. It uses reinforcement learning to perform multi-step thinking, self-correction, and logical deduction, matching top-tier commercial reasoning models in math and coding.', 'Coding', ARRAY['Mathematical reasoning', 'Complex code synthesis', 'Multi-step logic tasks', 'Scientific problem solving'], 'Freemium', 'Free open weights, ultra-low cost API', ARRAY['Open-source weights model', 'Chain-of-thought execution log', 'Unparalleled cost-efficiency', 'Multi-lingual support', 'High rate limits API'], ARRAY['Web', 'iOS', 'Android', 'API'], 'https://deepseek.com', 4.6, 3, 1303, true, NULL, 'deepseek-ai/DeepSeek-V3', 75.1),
  ('sora', 'Sora by OpenAI', 'Photorealistic text-to-video generation.', 'Sora is OpenAI''s state-of-the-art video generation model. It can generate videos up to a minute long while maintaining high visual quality and adherence to the user''s prompt, creating complex scenes with multiple characters and motion details.', 'Video Editing', ARRAY['Cinematic B-roll generation', 'Text to high-res video', 'Complex physical simulations', 'Ad campaign prototyping'], 'Paid', 'Custom plans and API pricing', ARRAY['60-second video duration', 'Camera tracking consistency', 'Multi-character scene parsing', 'Physics-inspired rendering', 'High-res widescreen output'], ARRAY['Web', 'API'], 'https://openai.com/sora', 4.7, 3, 1304, true, NULL, NULL, 73.3),
  ('adobe-firefly', 'Adobe Firefly', 'Commercial-safe creative generative models.', 'A family of creative generative AI models developed by Adobe, integrated directly into Photoshop and Illustrator. Trained exclusively on licensed content and public domain images, it ensures commercial safety for designers.', 'Image Generation', ARRAY['Generative fill in photos', 'Vector graphic generation', 'Text effects styling', 'Commercial design projects'], 'Freemium', 'Free generative credits, Premium from $4.99/mo', ARRAY['Adobe Creative Cloud sync', 'Commercially safe output', 'Inpainting and outpainting tools', 'Multi-lingual prompts', 'Content credentials metadata'], ARRAY['Web', 'Windows', 'macOS'], 'https://firefly.adobe.com', 4.6, 3, 1298, true, NULL, NULL, 75.8),
  ('suno', 'Suno AI', 'Generate complete songs and music in seconds.', 'Suno AI is a generative music platform that creates complete, studio-quality tracks—incorporating vocals, instrumentation, and lyrics—from simple textual descriptions. It enables video editors and hobbyists to create custom soundtracks in any genre.', 'Video Editing', ARRAY['Video soundtracks', 'Custom jingle generation', 'Song writing prototypes', 'Creative melody brainstorming'], 'Freemium', '50 daily credits free, Pro starts at $8/month', ARRAY['Vocals & instrument synthesis', 'Instrumental track selector', 'Custom lyrics editor', 'Genre model fine tuning', 'High-res audio exports'], ARRAY['Web', 'iOS', 'Discord'], 'https://suno.com', 4.3999999999999995, 3, 1291, true, NULL, NULL, 73.9),
  ('elevenlabs', 'ElevenLabs', 'Hyper-realistic AI voice generator and dubber.', 'ElevenLabs creates lifelike voiceovers, high-context text-to-speech, sound effects, and professional voice clones. Supporting dozens of languages and custom accents, it is the industry leader for audiobooks, video voice tracks, and game character dubbing.', 'Video Editing', ARRAY['Narrating scripts', 'Voice cloning', 'Multi-language dubbing', 'Audiobook production'], 'Freemium', '10,000 characters free monthly, tiers from $5/mo', ARRAY['High-fidelity speech synthesis', 'Emotional inflection slides', 'Instant voice cloning', 'Sound effects generation', 'Video localization dubs'], ARRAY['Web', 'API'], 'https://elevenlabs.io', 4.6, 3, 1293, true, NULL, NULL, 75.2),
  ('notebooklm', 'NotebookLM by Google', 'Your personalized AI collaborator and notes synthesizer.', 'NotebookLM is an experimental product by Google that acts as a personalized virtual research assistant. By uploading sources (PDFs, docs, slides, text files), it acts as an expert on that data, generating notes, guides, and incredibly realistic Audio Overviews (conversational podcasts).', 'Education', ARRAY['Research material synthesis', 'Podcast audio summaries', 'Study guide generation', 'Document Q&A references'], 'Free', 'Free to use in Google Labs', ARRAY['Source grounding (no hallucination)', 'Conversational audio discussion', 'Note-taking collaborative board', 'Google Docs integration', 'Citation references links'], ARRAY['Web'], 'https://notebooklm.google', 4.6, 3, 1303, true, NULL, NULL, 73.4),
  ('dall-e-3', 'DALL-E 3', 'State-of-the-art text to image by OpenAI.', 'OpenAI''s latest image generator, excels at following complex prompts and rendering precise layout details, text characters inside images, and following stylistic art directions natively.', 'Image Generation', ARRAY['Creative layout drawings', 'Illustrative artwork elements', 'Conceptual mockups design', 'Precision prompt following'], 'Paid', 'Included with ChatGPT Plus ($20/mo) or API usage', ARRAY['Exceptional prompt compliance', 'Spelled text formatting', 'Aspect ratio adjustment', 'Integrated inside ChatGPT', 'Safety filter guarding'], ARRAY['Web', 'iOS', 'Android', 'API'], 'https://openai.com/dall-e-3', 4.6, 3, 1308, true, NULL, NULL, 75.3),
